// src/components/Header.jsx
import React from 'react';
import { useTranslation } from '../context/TranslationContext';

export default function Header() {
  const { languageData, selectedLanguage, setLanguage } = useTranslation();

  const handleChange = (e) => {
    const lang = e.target.value;
    setLanguage(lang);
  };

  return (
    <header className="kiosk-header">
      <div className="kiosk-brand">
        <div className="kiosk-logo-orb" />
        <div className="kiosk-title-text">{languageData?.brand || 'Smart Kiosk'}</div>
      </div>
      <select value={selectedLanguage} onChange={handleChange} className="language-select">
        {Object.entries(languageData?.options || {}).map(([code, cfg]) => (
          <option key={code} value={code}>{cfg.name}</option>
        ))}
      </select>
    </header>
  );
}
